public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        if (edges.length == 0) {
            return 0;
        }

        long max_w = 0;
        for (long[] edge : edges) {
            if (edge[2] > max_w) {
                max_w = edge[2];
            }
        }

        long low = 0;
        long high = max_w;
        long answer = max_w;

        while (low <= high) {
            long mid = (low + high) / 2;
            DSU dsu = new DSU(n);
            for (long[] edge : edges) {
                long u = edge[0];
                long v = edge[1];
                long w = edge[2];
                if (w <= mid) {
                    dsu.union(u, v);
                }
            }
            long components = dsu.get_count();
            if (components <= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return answer;
    }

    static class DSU {
        long[] parent;
        long[] rank;
        long count;

        DSU(long size) {
            parent = new long[size];
            rank = new long[size];
            for (int i = 0; i < size; i++) {
                parent[i] = i;
                rank[i] = 0;
            }
            count = size;
        }

        long find(long x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        boolean union(long x, long y) {
            long xroot = find(x);
            long yroot = find(y);
            if (xroot == yroot) {
                return false;
            }
            if (rank[xroot] < rank[yroot]) {
                parent[xroot] = yroot;
            } else {
                parent[yroot] = xroot;
                if (rank[xroot] == rank[yroot]) {
                    rank[xroot]++;
                }
            }
            count--;
            return true;
        }

        long get_count() {
            return count;
        }
    }
}
